import { execution } from '@dynatrace-sdk/automation-utils';
import { entitiesClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const response = await entitiesClient.getEntity({
      id: input.entityId,
      fields: ['properties', 'tags', 'relations']
    });

    console.log(`Retrieved entity details for ${input.entityId}`);

    return {
      entityId: response.entityId,
      displayName: response.displayName || 'N/A',
      entityType: response.entityType || 'UNKNOWN',
      lastSeenTms: response.lastSeenTms ? new Date(response.lastSeenTms).toISOString() : 'N/A',
      firstSeenTms: response.firstSeenTms ? new Date(response.firstSeenTms).toISOString() : 'N/A',
      toRelationships: response.toRelationships ? response.toRelationships.length : 0,
      fromRelationships: response.fromRelationships ? response.fromRelationships.length : 0,
      tags: response.tags ? response.tags.length : 0,
      properties: response.properties || {}
    };
  } catch (error) {
    console.error('Error getting entity details:', error);
    throw new Error(`Failed to get entity details: ${error}`);
  }
}
